def main(alert):
    clickers = alert.get('clickers', alert.get('affected_users', []))
    if isinstance(clickers, str):
        clickers = [u.strip() for u in clickers.split(',') if u.strip()]
    unique_clickers = list(set(clickers))
    phishing_url = alert.get('url', alert.get('malicious_url', ''))
    return {
        'clickers': unique_clickers,
        'count': len(unique_clickers),
        'phishing_url': phishing_url,
        'campaign_id': alert.get('campaign_id', alert.get('name', 'unknown'))
    }

